+++ b/src/vs/base/common/strings.ts
@@ -223,7 +223,7 @@ export function createRegExp(searchString: string, isRegex: boolean, options: R
 	if (options.global) {
 		modifiers += 'g';
 	}
-	if (options.matchCase) {
+	if (!options.matchCase) {
 		modifiers += 'i';
 	}
 	if (options.multiline) {
"
  },
  {
    "file": "src/vs/editor/common/core/position.ts",
    "line": 103,
    "severity": "critical",
    "description": "The isBefore method has a boundary condition bug. Line 103 uses '<=' when it should use '<'. The method documentation states 'If the two positions are equal, the result will be false', but when positions are on the same line with equal columns, the current code returns true. This breaks cursor movement, undo/redo, and selection logic that depends on strict ordering.",
    "fix_patch": "--- a/src/vs/editor/common/core/position.ts
+++ b/src/vs/editor/common/core/position.ts
@@ -100,7 +100,7 @@ export class Position {
 		return false;
 	}
-	return a.column <= b.column;
+	return a.column < b.column;
 }

 	/**
"
  },
  {
    "file": "src/vs/editor/common/core/range.ts",
    "line": 97,
    "severity": "critical",
    "description": "The containsPosition method excludes the end position incorrectly. The docstring says 'If the position is at the edges, will return true', but line 97 uses '>=' instead of '>'. This means a position exactly at range.endColumn is excluded when it should be included. This breaks selection boundaries, find/replace highlighting, decorations, bracket matching, and any other feature using range containment checks.",
    "fix_patch": "--- a/src/vs/editor/common/core/range.ts
+++ b/src/vs/editor/common/core/range.ts
@@ -94,7 +94,7 @@ export class Range {
 		return false;
 	}
 	if (position.lineNumber === range.endLineNumber && position.column >= range.endColumn) {
 		return false;
 	}
 	return true;
"
  },
