    "file": "src/vs/editor/common/core/range.ts",
    "line": 97,
    "severity": "critical",
    "description": "The containsPosition method excludes the end position incorrectly. The docstring says 'If the position is at the edges, will return true', but line 97 uses '>=' instead of '>'. This means a position exactly at range.endColumn is excluded when it should be included. This breaks selection boundaries, find/replace highlighting, decorations, bracket matching, and any other feature using range containment checks.",
    "fix_patch": "--- a/src/vs/editor/common/core/range.ts
+++ b/src/vs/editor/common/core/range.ts
@@ -94,7 +94,7 @@ export class Range {
 		return false;
 	}
-	if (position.lineNumber === range.endLineNumber && position.column >= range.endColumn) {
+	if (position.lineNumber === range.endLineNumber && position.column > range.endColumn) {
 		return false;
 	}
 	return true;
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 490,
    "severity": "critical",
    "description": "The isValidMatch function for whole-word search uses OR (||) instead of AND (&&). For a match to be a valid whole word, BOTH the left and right sides must be word boundaries. Currently, the function returns true if either side is a boundary, which allows partial word matches when whole-word search is enabled. This breaks the 'Match Whole Word' feature in find/replace.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -487,7 +487,7 @@ function rightIsWordBounday(wordSeparators: WordCharacterClassifier, text: stri

 export function isValidMatch(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
 	return (
-		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
-		|| rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		leftIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
+		&& rightIsWordBounday(wordSeparators, text, textLength, matchStartIndex, matchLength)
 	);
 }
"
  },
  {
    "file": "src/vs/editor/common/languageFeatureRegistry.ts",
    "line": 195,
    "severity": "critical",
    "description": "The score comparison in _compareByScoreAndTime is reversed. The function should prioritize higher scores first (lower indices in sorted array), but when a._score < b._score, it returns -1, making the lower-score entry come first. This inverts the priority of all language feature providers (completions, hover, diagnostics, etc.), causing lower-quality providers to be prioritized over higher-quality ones.",
    "fix_patch": "--- a/src/vs/editor/common/languageFeatureRegistry.ts
+++ b/src/vs/editor/common/languageFeatureRegistry.ts
@@ -192,10 +192,10 @@ export class LanguageFeatureRegistry<T> {
 	}

 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
-		if (a._score < b._score) {
+		if (a._score > b._score) {
 			return -1;
-		} else if (a._score > b._score) {
+		} else if (a._score < b._score) {
 			return 1;
 		}

"
  }
]

